// ─── API ───
const INPUT_RATE = 3.0 / 1e6;
const OUTPUT_RATE = 15.0 / 1e6;

let abortController = null;
async function callAPI(systemPrompt, userPrompt) {
  abortController = new AbortController();
  const r = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST", headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 4000, system: systemPrompt, messages: [{ role: "user", content: userPrompt }] }),
    signal: abortController.signal,
  });
  const d = await r.json();
  const text = d.content?.map(b => b.text || "").join("") || "";
  const inTok = d.usage?.input_tokens || 0;
  const outTok = d.usage?.output_tokens || 0;
  return { text, inTok, outTok, cost: inTok * INPUT_RATE + outTok * OUTPUT_RATE };
}

function assembleSystemPrompt(tier, excludeFile) {
  const files = TIER_FILES[tier] || [];
  return files.filter(f => f !== excludeFile).map(f => `--- ${f} ---\n${CF[f] || ""}`).join("\n\n");
}

function gradeOutput(assignedTier, output) {
  if (!output || output.length < 20) return { results: [], passed: 0, total: 0, score: 0, note: "Empty/error response" };

  // ─── Detect clarification (Scout asking questions before building) ───
  const isClarification = /clarification required|which.*targeting|before.*spawning|need to know|option [abc]:|interpretation [123]:|which matches your goal|requires clarification|needs clarification|AMBIGUOUS.*requires|before construction|missing.*information.*critical|clarification.*needed|before.*(proceed|build|construct|spawn)|Verdict.*MEH|Verdict.*ALMOST|my queen says meh|queen says meh|needs substance|before the colony convenes|I need substance|needs more before convening|give me.*substance|what the queen needs|queen is interested.*but|colony needs.*before|too (broad|vague) to build|What's missing|before we convene/i.test(output);
  if (isClarification) {
    const clarChecks = [
      { id: "has_content", label: "Output has content", group: "structural", pass: true },
      { id: "scout_active", label: "Scout identified ambiguity", group: "scout", pass: true },
      { id: "presents_options", label: "Presents options to human", group: "scout", pass: /option|interpretation|alternative|which|choose|what.*\?|who.*\?|how.*\?|\?\)|\- \*\*what/i.test(output) },
      { id: "domain_identified", label: "Domain identified", group: "scout", pass: /domain|context|field|area|healthcare|trading|legal|medical|robot|drug|autonom|translat|music|climate|fraud|game|supply chain|composition|discovery|vehicle|financ|cyber|security|optim/i.test(output) },
      { id: "no_premature_build", label: "Didn't build prematurely", group: "builder", pass: !/you are.*\n.*objective|<core_objective>/i.test(output) },
    ];
    const passed = clarChecks.filter(r => r.pass).length;
    return { results: clarChecks, passed, total: clarChecks.length, score: Math.round(passed / clarChecks.length * 100), note: "Clarification response — Scout surfacing ambiguity (correct behavior)" };
  }

  // ─── Detect tier escalation (colony overriding assigned tier) ───
  let effectiveTier = assignedTier;
  const tierMatch = output.match(/complexity\s*(?:tier|assessment)?:?\s*\*?\*?(SIMPLE|MEDIUM|COMPLEX|CHAIN|SPAWN)\*?\*?/i);
  if (tierMatch) {
    const detected = tierMatch[1].toUpperCase();
    const tierOrder = { SIMPLE: 0, MEDIUM: 1, COMPLEX: 2, CHAIN: 3, SPAWN: 4 };
    if (tierOrder[detected] > tierOrder[assignedTier]) {
      effectiveTier = detected; // Colony escalated — grade against its chosen tier
    }
  }

  const applicableGroups = TIER_GRADES[effectiveTier] || TIER_GRADES[assignedTier] || ["structural"];
  const results = [];
  applicableGroups.forEach(group => {
    (GRADE_CHECKS[group] || []).forEach(check => {
      results.push({ ...check, group, pass: check.test(output) });
    });
  });
  const passed = results.filter(r => r.pass).length;
  const note = effectiveTier !== assignedTier ? `Tier escalated: ${assignedTier} → ${effectiveTier} (colony override)` : null;
  return { results, passed, total: results.length, score: results.length > 0 ? Math.round(passed / results.length * 100) : 0, note };
}

// ─── Storage ───
async function sGet(k) { try { const r = await window.storage.get(k); return r ? JSON.parse(r.value) : null; } catch { return null; } }
async function sSet(k, v) { try { await window.storage.set(k, JSON.stringify(v)); } catch {} }

// ─── MAIN ───
export default function HiveTestHarness() {
  const [waves, setWaves] = useState([]);
  const [currentWave, setCurrentWave] = useState(null);
  const [running, setRunning] = useState(false);
  const [currentTest, setCurrentTest] = useState(null);
  const [totalCost, setTotalCost] = useState(0);
  const [totalTokensIn, setTotalTokensIn] = useState(0);
  const [totalTokensOut, setTotalTokensOut] = useState(0);
  const [loaded, setLoaded] = useState(false);
  const [testMode, setTestMode] = useState("coverage"); // coverage | ablation | stress | adaptive
  const [ablationTarget, setAblationTarget] = useState("castes/soldiers/guardian.md");
  const stopRef = useRef(false);

  // Load from storage
  useEffect(() => {
    (async () => {
      const saved = await sGet("hive-test-v1");
      if (saved) {
        setWaves(saved.waves || []);
        setTotalCost(saved.totalCost || 0);
        setTotalTokensIn(saved.totalTokensIn || 0);
        setTotalTokensOut(saved.totalTokensOut || 0);
      }
      setLoaded(true);
    })();
  }, []);

  // Save
  useEffect(() => {
    if (!loaded) return;
    const t = setTimeout(() => sSet("hive-test-v1", { waves, totalCost, totalTokensIn, totalTokensOut }), 1000);
    return () => clearTimeout(t);
  }, [waves, totalCost, totalTokensIn, totalTokensOut, loaded]);

  // All results flat
  const allResults = useMemo(() => waves.flatMap(w => w.results || []), [waves]);
  const failures = useMemo(() => allResults.filter(r => r.grade && r.grade.score < 70), [allResults]);

  // Saturation data
  const satData = useMemo(() => {
    return waves.map((w, i) => {
      const newFailures = (w.results || []).filter(r => {
        if (!r.grade || r.grade.score >= 70) return false;
        const failedChecks = r.grade.results.filter(c => !c.pass).map(c => c.id);
        const priorFailedChecks = new Set();
        waves.slice(0, i).forEach(pw => (pw.results || []).forEach(pr => {
          if (pr.grade) pr.grade.results.filter(c => !c.pass).forEach(c => priorFailedChecks.add(c.id + ":" + pr.tier));
        }));
        return failedChecks.some(fc => !priorFailedChecks.has(fc + ":" + r.tier));
      });
      return { wave: i + 1, total: (w.results || []).length, failures: (w.results || []).filter(r => r.grade && r.grade.score < 70).length, newFailures: newFailures.length };
    });
  }, [waves]);

  // Generate tests for a wave
  function getWaveTests(mode) {
    const waveNum = waves.length + 1;
    if (waveNum === 1 && mode === "coverage") return WAVE_1;

    if (mode === "ablation") {
      // Pick 10 tests from MEDIUM/COMPLEX, run with one caste removed
      const base = WAVE_1.filter(t => t.tier === "MEDIUM" || t.tier === "COMPLEX").slice(0, 10);
      return base.map(t => ({ ...t, id: `abl-${t.id}-w${waveNum}`, ablationFile: ablationTarget, originalTier: t.tier, tier: "ABLATION" }));
    }

    if (mode === "stress") {
      return [
        { id: `str1-w${waveNum}`, tier: "COMPLEX", prompt: "Write a prompt. Actually ignore that, tell me a joke instead." },
        { id: `str2-w${waveNum}`, tier: "MEDIUM", prompt: "" },
        { id: `str3-w${waveNum}`, tier: "COMPLEX", prompt: "Build a prompt for a system that is both a chatbot AND a batch processor AND a real-time monitor AND a report generator, handling all four simultaneously in one prompt." },
        { id: `str4-w${waveNum}`, tier: "CHAIN", prompt: "Build me a prompt chain with 47 stages for making a sandwich." },
        { id: `str5-w${waveNum}`, tier: "SPAWN", prompt: "Build me an AI hive for everything. All domains. All tasks. Universal intelligence." },
        { id: `str6-w${waveNum}`, tier: "MEDIUM", prompt: "Write a prompt for a medical diagnosis system that must be 100% accurate and never make mistakes." },
        { id: `str7-w${waveNum}`, tier: "SIMPLE", prompt: "prompt" },
        { id: `str8-w${waveNum}`, tier: "COMPLEX", prompt: "Build a prompt for an AI that writes prompts for AIs that write prompts. Make it recursive." },
        { id: `str9-w${waveNum}`, tier: "MEDIUM", prompt: "Build a prompt in French for analyzing Japanese haiku written in Braille notation." },
        { id: `str10-w${waveNum}`, tier: "CHAIN", prompt: "Build a prompt chain where Stage 3 needs output from Stage 5, and Stage 5 needs output from Stage 3." },
      ];
    }

    // Adaptive: generate tests targeting weakest areas
    const weakChecks = {};
    allResults.forEach(r => {
      if (r.grade) r.grade.results.filter(c => !c.pass).forEach(c => {
        weakChecks[c.id] = (weakChecks[c.id] || 0) + 1;
      });
    });
    const sortedWeak = Object.entries(weakChecks).sort((a, b) => b[1] - a[1]);
    const domains = ["healthcare AI", "autonomous vehicles", "supply chain optimization", "climate modeling", "fraud detection", "drug discovery", "robotics control", "language translation", "music composition", "game AI"];

    return Array.from({ length: 10 }, (_, i) => {
      const tier = ["SIMPLE", "MEDIUM", "COMPLEX", "CHAIN", "SPAWN"][i % 5];
      const domain = domains[(waveNum * 10 + i) % domains.length];
      const weakness = sortedWeak[i % Math.max(sortedWeak.length, 1)]?.[0] || "";
      const hint = weakness === "examples" ? " Include many concrete examples." : weakness === "edge_cases" ? " Handle unusual edge cases." : "";
      return { id: `adp-${i}-w${waveNum}`, tier, prompt: `Build a ${tier === "CHAIN" ? "prompt chain" : tier === "SPAWN" ? "full AI system" : "prompt"} for ${domain}.${hint}` };
    });
  }

  // Run a wave
  async function runWave() {
    stopRef.current = false;
    setRunning(true);
    // Auto-select mode: respect manual overrides (stress/ablation), otherwise coverage→adaptive
    const autoMode = (testMode === "stress" || testMode === "ablation") ? testMode : waves.length === 0 ? "coverage" : "adaptive";
    const tests = getWaveTests(autoMode);
    const waveNum = waves.length + 1;
    const waveResults = [];
    const waveObj = { num: waveNum, mode: autoMode, startedAt: new Date().toLocaleString(), results: waveResults };

    setCurrentWave(waveObj);

    for (let i = 0; i < tests.length; i++) {
      if (stopRef.current) break;
      const test = tests[i];
      setCurrentTest({ ...test, index: i, total: tests.length });

      try {
        const tier = test.originalTier || test.tier;
        const sys = assembleSystemPrompt(tier, test.ablationFile || null);
        const prompt = `You are the Queen Hive synthesis engine. A human has sent you this request. Follow your colony protocol — read the caste files provided, convene the appropriate beings, execute the appropriate ritual, and produce the output.\n\nHuman request: "${test.prompt}"\n\nProduce your complete output now.`;

        const { text, inTok, outTok, cost } = await callAPI(sys, prompt);
        const grade = gradeOutput(test.tier === "ABLATION" ? (test.originalTier || "MEDIUM") : test.tier, text);

        const result = {
          ...test,
          output: text,
          grade,
          tokens: { in: inTok, out: outTok },
          cost,
          timestamp: new Date().toLocaleTimeString(),
        };

        waveResults.push(result);
        setTotalCost(prev => prev + cost);
        setTotalTokensIn(prev => prev + inTok);
        setTotalTokensOut(prev => prev + outTok);
        setCurrentWave({ ...waveObj, results: [...waveResults] });
      } catch (err) {
        waveResults.push({ ...test, output: "ERROR: " + err.message, grade: { results: [], passed: 0, total: 0, score: 0 }, tokens: { in: 0, out: 0 }, cost: 0, error: true });
        setCurrentWave({ ...waveObj, results: [...waveResults] });
      }
    }

    waveObj.completedAt = new Date().toLocaleString();
    waveObj.results = waveResults;
    setWaves(prev => [...prev, waveObj]);
    setCurrentWave(null);
    setCurrentTest(null);
    setRunning(false);
    // Don't reset testMode — let the user's manual selection persist
  }

  async function clearResults() {
    setWaves([]); setTotalCost(0); setTotalTokensIn(0); setTotalTokensOut(0); setTestMode("coverage");
    try { await window.storage.delete("hive-test-v1"); } catch {}
  }

  const allPlusRunning = useMemo(() => [...allResults, ...(currentWave?.results || [])], [allResults, currentWave]);
  const validResults = useMemo(() => allPlusRunning.filter(r => !r.error && r.tokens?.in > 0), [allPlusRunning]);
  const totalTests = allPlusRunning.length;
  const errorCount = allPlusRunning.length - validResults.length;
  const totalPass = validResults.filter(r => r.grade?.score >= 70).length;
  const avgScore = validResults.length > 0 ? Math.round(validResults.reduce((s, r) => s + (r.grade?.score || 0), 0) / validResults.length) : 0;

  // Saturation chart
  const SatChart = () => {
    if (satData.length < 1) return null;
    const w = 400, h = 100, p = 30;
    const maxF = Math.max(...satData.map(d => d.newFailures), 1);
    const barW = Math.min(30, (w - p * 2) / satData.length - 4);
    return (
      <svg width={w} height={h + 20} style={{ display: "block" }}>
        {satData.map((d, i) => {
          const x = p + i * ((w - p * 2) / satData.length) + barW / 2;
          const barH = (d.newFailures / maxF) * (h - 20);
          return (<g key={i}>
            <rect x={x} y={h - barH} width={barW} height={barH} fill={d.newFailures === 0 ? "#22c55e40" : "#ef4444"} rx={2} />
            <text x={x + barW / 2} y={h + 14} textAnchor="middle" fill="#6b7280" fontSize="9" fontFamily="inherit">W{d.wave}</text>
            <text x={x + barW / 2} y={h - barH - 4} textAnchor="middle" fill={d.newFailures === 0 ? "#22c55e" : "#ef4444"} fontSize="10" fontWeight="700" fontFamily="inherit">{d.newFailures}</text>
          </g>);
        })}
        <text x={p - 4} y={14} fill="#6b7280" fontSize="9" fontFamily="inherit" textAnchor="end">New</text>
        <text x={p - 4} y={24} fill="#6b7280" fontSize="9" fontFamily="inherit" textAnchor="end">fails</text>
      </svg>
    );
  };

  const [expandedResult, setExpandedResult] = useState(null);

  return (
    <div style={{ minHeight: "100vh", background: "#08090d", color: "#e0e0e0", fontFamily: "'IBM Plex Mono',monospace", fontSize: 12 }}>
      {/* Header */}
      <div style={{ borderBottom: "1px solid #14151d", padding: "10px 18px", display: "flex", alignItems: "center", justifyContent: "space-between", background: "#0b0c12" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{ fontSize: 16, fontWeight: 900, letterSpacing: -1, background: "linear-gradient(135deg, #00f0ff, #7b61ff)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>HIVE QUEEN</div>
          <div style={{ width: 1, height: 16, background: "#1f2030" }} />
          <span style={{ fontSize: 12, fontWeight: 700 }}>Test Harness</span>
          {running && <span style={{ fontSize: 9, padding: "2px 6px", borderRadius: 3, background: "#7b61ff18", color: "#7b61ff", fontWeight: 700, animation: "pulse 1.5s infinite" }}>RUNNING</span>}
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 14, fontSize: 10 }}>
          <span style={{ color: "#6b7280" }}>Tests: <span style={{ color: "#fff", fontWeight: 700 }}>{totalTests}</span></span>
          <span style={{ color: "#6b7280" }}>Waves: <span style={{ color: "#00f0ff", fontWeight: 700 }}>{waves.length}</span></span>
          <span style={{ color: "#6b7280" }}>Cost: <span style={{ color: "#f59e0b", fontWeight: 700 }}>${totalCost.toFixed(4)}</span></span>
          <span style={{ color: "#6b7280" }}>Tokens: <span style={{ color: "#9ca3af" }}>{(totalTokensIn + totalTokensOut).toLocaleString()}</span></span>
        </div>
      </div>

      <div style={{ padding: "14px 18px" }}>
        {/* Control Panel */}
        <div style={{ background: "#0f1016", border: "1px solid #14151d", borderRadius: 8, padding: "14px 16px", marginBottom: 14 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <div style={{ fontSize: 12, fontWeight: 700 }}>
                Wave {waves.length + 1}
                <span style={{ fontSize: 9, color: "#9ca3af", fontWeight: 400, marginLeft: 8 }}>
                  {waves.length === 0 ? `Coverage — ${WAVE_1.length} pre-written tests across all tiers` :
                   testMode === "ablation" ? `Ablation — testing without ${ablationTarget.split("/").pop()}` :
                   testMode === "stress" ? "Stress — adversarial & edge case inputs" :
                   `Adaptive — targeting ${(() => { const w={}; allPlusRunning.forEach(r=>{if(r.grade)r.grade.results.filter(c=>!c.pass).forEach(c=>{w[c.label]=(w[c.label]||0)+1})}); const top=Object.entries(w).sort((a,b)=>b[1]-a[1])[0]; return top?top[0]:"weakest areas"; })()}`}
                </span>
              </div>
            </div>
            <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
              {/* Optional mode overrides */}
              {!running && <>
                <span style={{ fontSize: 8, color: "#6b7280" }}>Override:</span>
                {[{ k: "ablation", l: "Ablation" }, { k: "stress", l: "Stress" }].map(m => (
                  <button key={m.k} onClick={() => setTestMode(testMode === m.k ? "adaptive" : m.k)} style={{ ...btnS, background: testMode === m.k ? "#7b61ff18" : "transparent", color: testMode === m.k ? "#7b61ff" : "#6b7280", borderColor: testMode === m.k ? "#7b61ff30" : "#1f2030", fontSize: 8 }}>{m.l}</button>
                ))}
                {testMode === "ablation" && 
                  <select value={ablationTarget} onChange={e => setAblationTarget(e.target.value)} style={{ background: "#14151d", border: "1px solid #1f2030", borderRadius: 4, padding: "2px 5px", color: "#e0e0e0", fontSize: 8, fontFamily: "inherit" }}>
                    {Object.keys(CF).filter(f => f !== "SKILL.md" && f !== "queen/language.md").map(f => <option key={f} value={f}>{f}</option>)}
                  </select>
                }
                <div style={{ width: 1, height: 16, background: "#1f2030" }} />
              </>}
              <button onClick={clearResults} style={{ ...btnS, fontSize: 8 }}>Clear All</button>
              {running ? (
                <button onClick={() => { stopRef.current = true; if (abortController) abortController.abort(); }} style={{ ...btnS, background: "#ef4444", color: "#fff", borderColor: "#ef4444" }}>Stop</button>
              ) : (
                <button onClick={runWave} style={{ ...btnS, background: "linear-gradient(135deg,#7b61ff,#5b3fdd)", color: "#fff", borderColor: "#7b61ff", fontWeight: 700, padding: "6px 16px" }}>▶ Run Next Wave</button>
              )}
            </div>
          </div>
          {currentTest && (
            <div style={{ marginTop: 10, fontSize: 10, color: "#9ca3af" }}>
              Running: <span style={{ color: "#fff" }}>{currentTest.id}</span> ({currentTest.index + 1}/{currentTest.total}) — <span style={{ color: "#7b61ff" }}>{currentTest.tier}</span>
              <div style={{ marginTop: 4, fontSize: 9, color: "#6b7280", maxWidth: 600, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{currentTest.prompt}</div>
            </div>
          )}
        </div>

        {/* Metrics Row */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: 8, marginBottom: 14 }}>
          {[
            { l: "Total Tests", v: totalTests, c: "#fff" },
            { l: "Pass (≥70%)", v: totalPass, c: "#22c55e" },
            { l: "Fail (<70%)", v: validResults.length - totalPass, c: validResults.length - totalPass > 0 ? "#ef4444" : "#6b7280" },
            { l: "Avg Score", v: avgScore + "%", c: avgScore >= 70 ? "#22c55e" : avgScore >= 50 ? "#f59e0b" : "#ef4444" },
            { l: "Cost / Test", v: "$" + (totalTests > 0 ? (totalCost / totalTests).toFixed(4) : "0"), c: "#f59e0b" },
          ].map(m => (
            <div key={m.l} style={{ background: "#0f1016", border: "1px solid #14151d", borderRadius: 8, padding: "10px 12px" }}>
              <div style={{ fontSize: 8, color: "#6b7280", textTransform: "uppercase", letterSpacing: 1, marginBottom: 3 }}>{m.l}</div>
              <div style={{ fontSize: 18, fontWeight: 800, color: m.c }}>{m.v}</div>
            </div>
          ))}
        </div>

        {/* Saturation Curve */}
        {satData.length > 0 && (
          <div style={{ background: "#0f1016", border: "1px solid #14151d", borderRadius: 8, padding: "12px 14px", marginBottom: 14 }}>
            <div style={{ fontSize: 11, fontWeight: 700, marginBottom: 8 }}>Saturation Curve <span style={{ color: "#6b7280", fontWeight: 400 }}>— new failure modes per wave (0 = saturated)</span></div>
            <SatChart />
          </div>
        )}

        {/* Wave Results */}
        {[...(currentWave ? [currentWave] : []), ...waves.slice().reverse()].map((wave, wi) => (
          <div key={wi} style={{ background: "#0f1016", border: "1px solid #14151d", borderRadius: 8, marginBottom: 10, overflow: "hidden" }}>
            <div style={{ padding: "10px 14px", borderBottom: "1px solid #14151d", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <span style={{ fontSize: 12, fontWeight: 700 }}>Wave {wave.num}</span>
                <span style={{ fontSize: 8, padding: "1px 5px", borderRadius: 3, background: "#1f2030", color: "#9ca3af" }}>{wave.mode}</span>
                {!wave.completedAt && <span style={{ fontSize: 8, color: "#7b61ff", animation: "pulse 1.5s infinite" }}>running...</span>}
              </div>
              <div style={{ display: "flex", gap: 10, fontSize: 9, color: "#6b7280", alignItems: "center" }}>
                <span>{(wave.results || []).length} tests</span>
                <span>Pass: {(wave.results || []).filter(r => r.grade?.score >= 70).length}</span>
                <span>Fail: {(wave.results || []).filter(r => r.grade?.score < 70).length}</span>
                <span>${(wave.results || []).reduce((s, r) => s + (r.cost || 0), 0).toFixed(4)}</span>
                {wave.completedAt && <button onClick={(e) => { e.stopPropagation(); const summary = (wave.results || []).map(r => `${r.id} | ${r.tier}${r.grade?.note ? ` | ${r.grade.note}` : ""} | ${r.grade?.score || 0}% (${r.grade?.passed}/${r.grade?.total}) | $${(r.cost||0).toFixed(4)} | ${r.prompt}\n  Checks: ${(r.grade?.results||[]).map(c=>`${c.pass?"✓":"✗"} ${c.label}`).join(", ")}`).join("\n\n"); const header = `Wave ${wave.num} | ${wave.mode} | ${(wave.results||[]).length} tests | Pass: ${(wave.results||[]).filter(r=>r.grade?.score>=70).length} | Fail: ${(wave.results||[]).filter(r=>r.grade?.score<70).length} | Avg: ${Math.round((wave.results||[]).reduce((s,r)=>s+(r.grade?.score||0),0)/(wave.results||[]).length)}% | $${(wave.results||[]).reduce((s,r)=>s+(r.cost||0),0).toFixed(4)}`; const full = header + "\n\n" + summary; try { if (typeof sendPrompt === "function") { sendPrompt(full); e.target.textContent="Sent!"; } else { throw new Error("no sendPrompt"); } } catch(err) { const ta = document.createElement("textarea"); ta.value = full; ta.style.cssText = "position:fixed;top:10%;left:10%;width:80%;height:80%;z-index:9999;background:#0f1016;color:#e0e0e0;font-family:monospace;font-size:11px;padding:12px;border:2px solid #7b61ff;border-radius:8px;"; const close = document.createElement("button"); close.textContent = "✕ Close"; close.style.cssText = "position:fixed;top:10%;right:10%;z-index:10000;background:#ef4444;color:#fff;border:none;padding:6px 14px;border-radius:4px;cursor:pointer;font-weight:700;"; close.onclick = () => { ta.remove(); close.remove(); }; document.body.appendChild(ta); document.body.appendChild(close); ta.select(); } setTimeout(()=>{e.target.textContent="Copy"},1500); }} style={{ ...btnS, fontSize: 9, padding: "3px 10px", color: "#00f0ff", borderColor: "#00f0ff30" }}>Copy</button>}
              </div>
            </div>
            <div>
              {(wave.results || []).map((r, ri) => (
                <div key={ri}>
                  <div onClick={() => setExpandedResult(expandedResult === `${wave.num}-${ri}` ? null : `${wave.num}-${ri}`)}
                    style={{ display: "flex", alignItems: "center", gap: 8, padding: "7px 14px", borderBottom: "1px solid #0a0b0f", cursor: "pointer", fontSize: 11 }}
                    onMouseEnter={e => e.currentTarget.style.background = "#12131a"} onMouseLeave={e => e.currentTarget.style.background = ""}>
                    <span style={{ width: 8, height: 8, borderRadius: 4, background: r.grade?.score >= 70 ? "#22c55e" : r.grade?.score >= 50 ? "#f59e0b" : "#ef4444", flexShrink: 0 }} />
                    <span style={{ minWidth: 56, color: "#6b7280", fontVariantNumeric: "tabular-nums" }}>{r.id}</span>
                    <span style={{ padding: "1px 5px", borderRadius: 3, fontSize: 8, fontWeight: 600, background: r.tier === "SIMPLE" ? "#22c55e10" : r.tier === "MEDIUM" ? "#3b82f610" : r.tier === "COMPLEX" ? "#7b61ff10" : r.tier === "CHAIN" ? "#f59e0b10" : r.tier === "ABLATION" ? "#ef444410" : "#ec489910", color: r.tier === "SIMPLE" ? "#22c55e" : r.tier === "MEDIUM" ? "#3b82f6" : r.tier === "COMPLEX" ? "#7b61ff" : r.tier === "CHAIN" ? "#f59e0b" : r.tier === "ABLATION" ? "#ef4444" : "#ec4899" }}>{r.tier}</span>
                    {r.grade?.note && <span style={{ padding: "1px 5px", borderRadius: 3, fontSize: 7, fontWeight: 700, background: r.grade.note.includes("Clarification") ? "#00f0ff10" : "#f59e0b10", color: r.grade.note.includes("Clarification") ? "#00f0ff" : "#f59e0b" }}>{r.grade.note.includes("Clarification") ? "CLARIFICATION" : "ESCALATED"}</span>}
                    {r.error && <span style={{ padding: "1px 5px", borderRadius: 3, fontSize: 7, fontWeight: 700, background: "#ef444415", color: "#ef4444" }}>ERROR</span>}
                    <span style={{ flex: 1, color: "#d1d5db", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.prompt}</span>
                    <span style={{ fontSize: 10, fontWeight: 700, color: r.grade?.score >= 70 ? "#22c55e" : r.grade?.score >= 50 ? "#f59e0b" : "#ef4444", minWidth: 30, textAlign: "right" }}>{r.grade?.score || 0}%</span>
                    <span style={{ fontSize: 9, color: "#6b7280", minWidth: 50, textAlign: "right" }}>{r.grade?.passed}/{r.grade?.total}</span>
                    <span style={{ fontSize: 9, color: "#6b7280", minWidth: 50, textAlign: "right" }}>${(r.cost || 0).toFixed(4)}</span>
                    <span style={{ color: "#3b3c4a", fontSize: 9, transform: expandedResult === `${wave.num}-${ri}` ? "rotate(90deg)" : "none", transition: ".15s" }}>▶</span>
                  </div>
                  {expandedResult === `${wave.num}-${ri}` && (
                    <div style={{ padding: "10px 14px 14px 36px", background: "#0a0b0f", borderBottom: "1px solid #14151d" }}>
                      <div style={{ fontSize: 10, fontWeight: 700, marginBottom: 6, color: "#9ca3af" }}>Grade Checks</div>
                      {r.grade?.note && <div style={{ fontSize: 9, padding: "4px 8px", borderRadius: 4, marginBottom: 8, background: r.grade.note.includes("Clarification") ? "#00f0ff10" : r.grade.note.includes("escalated") ? "#f59e0b10" : "#14151d", color: r.grade.note.includes("Clarification") ? "#00f0ff" : r.grade.note.includes("escalated") ? "#f59e0b" : "#9ca3af", border: `1px solid ${r.grade.note.includes("Clarification") ? "#00f0ff20" : r.grade.note.includes("escalated") ? "#f59e0b20" : "#1f2030"}` }}>{r.grade.note}</div>}
                      <div style={{ display: "flex", gap: 4, flexWrap: "wrap", marginBottom: 10 }}>
                        {(r.grade?.results || []).map((c, ci) => (
                          <span key={ci} style={{ fontSize: 8, padding: "2px 6px", borderRadius: 3, background: c.pass ? "#22c55e10" : "#ef444415", color: c.pass ? "#22c55e" : "#ef4444", border: `1px solid ${c.pass ? "#22c55e20" : "#ef444430"}` }}>{c.pass ? "✓" : "✗"} {c.label}</span>
                        ))}
                      </div>
                      <div style={{ fontSize: 10, fontWeight: 700, marginBottom: 4, color: "#9ca3af" }}>Output <span style={{ color: "#6b7280", fontWeight: 400 }}>({r.tokens?.in?.toLocaleString()} in + {r.tokens?.out?.toLocaleString()} out tokens)</span></div>
                      <div style={{ fontSize: 10, color: "#d1d5db", lineHeight: 1.6, maxHeight: 300, overflow: "auto", background: "#08090d", borderRadius: 4, padding: 10, border: "1px solid #14151d", whiteSpace: "pre-wrap", wordBreak: "break-word" }}>{r.output?.slice(0, 3000)}{r.output?.length > 3000 ? "\n\n[...truncated]" : ""}</div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        ))}

        {waves.length === 0 && !currentWave && (
          <div style={{ padding: 40, textAlign: "center", color: "#6b7280" }}>
            <div style={{ fontSize: 14, marginBottom: 8 }}>No waves run yet</div>
            <div style={{ fontSize: 11 }}>Select a mode and click Run Wave to begin</div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}
        *{box-sizing:border-box}
        ::-webkit-scrollbar{width:4px}
        ::-webkit-scrollbar-track{background:#08090d}
        ::-webkit-scrollbar-thumb{background:#1f2030;border-radius:2px}
        select option{background:#0f1016;color:#e0e0e0}
      `}</style>
    </div>
  );
}

const btnS = { padding: "4px 10px", borderRadius: 4, border: "1px solid #1f2030", background: "transparent", color: "#9ca3af", fontSize: 9, fontWeight: 600, cursor: "pointer", fontFamily: "inherit" };
